steps.script:
var ul = tree.root.get_node("/root/Main/HUD_Right/VBoxContainer/MovementScrollContainer/MovementPanel/Section1_UnitList/MovementUnitList")
var sb = ul.get_v_scroll_bar()
sb.value = 0.0
var rect7 = ul.get_item_rect(7)
sb.value = clamp(rect7.position.y - 10.0, 0.0, sb.max_value)
return true

var d = tree.root.get_node_or_null("DisembarkDialog")
if d == null:
	return "NO DIALOG"
d.get_ok_button().emit_signal("pressed")
return "ok"

var live = []
for c in tree.get_nodes_in_group("disembark_controllers"):
	if is_instance_valid(c) and not c._finished:
		live.append(c)
if live.size() != 1:
	return "live=%d" % live.size()
var c = live[0]
if c.transport_id != "U_BATTLEWAGON_A":
	return "transport=%s" % c.transport_id
if absf(c.transport_rotation - 0.6) > 0.001:
	return "rot=%f" % c.transport_rotation
var tm = c.transport_data.models[0]
var line = c.range_indicator.get_child(0).get_child(0)
if line.points.size() < 40:
	return "points=%d" % line.points.size()
var max_dev = 0.0
for p in line.points:
	var dist = Measurement.model_edge_to_point_distance_px(tm, p)
	max_dev = maxf(max_dev, absf(dist - Measurement.inches_to_px(3.0)))
if max_dev > 1.5:
	return "max_dev=%f" % max_dev
return "border-exact"

var live = 0
for c in tree.get_nodes_in_group("disembark_controllers"):
	if is_instance_valid(c) and not c._finished:
		live += 1
return live

var d = tree.root.get_node_or_null("DisembarkDialog")
if d == null:
	return "NO DIALOG"
d.get_ok_button().emit_signal("pressed")
return "ok"

var live = []
for c in tree.get_nodes_in_group("disembark_controllers"):
	if is_instance_valid(c) and not c._finished:
		live.append(c)
if live.size() != 1:
	return "live=%d" % live.size()
return live[0].transport_id

var live = 0
for c in tree.get_nodes_in_group("disembark_controllers"):
	if is_instance_valid(c) and not c._finished:
		live += 1
return live
